// EmergencyProfile Component
// Displays emergency profile based on URL parameter

import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import "./App.css";

function EmergencyProfile() {
  const { patientId } = useParams();

  const [data, setData] = useState(null);
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(`/emergency/${patientId}`)
      .then((response) => response.json())
      .then((result) => {
        setLoading(false);

        if (result.message) {
          setMessage(result.message);
        } else {
          setData(result);
        }
      })
      .catch(() => {
        setLoading(false);
        setMessage("Server not reachable");
      });
  }, [patientId]);

  // Loading Animation
  if (loading) {
    return (
      <div className="loader-container">
        <div className="loader"></div>
        <p>Loading Emergency Profile...</p>
      </div>
    );
  }

  // Message Handling
  if (message === "Profile not public visible") {
    return <div className="message">Profile is not visible</div>;
  }

  if (message === "No record found") {
    return <div className="message">No record found</div>;
  }

  if (message) {
    return <div className="message">{message}</div>;
  }

  // Profile Display
  return (
    <>
      <div className="header">
        🚑 Emergency Medical Profile
      </div>

      <div className="container">
        <div className="card">
          <p><strong>Name:</strong> {data.name}</p>
          <p><strong>Address:</strong> {data.address}</p>
          <p><strong>Gender:</strong> {data.gender}</p>
          <p><strong>Contact Name:</strong> {data.contact_name}</p>
          <p><strong>Contact Phone:</strong> {data.contact_phone}</p>
          <p><strong>Chronic Conditions:</strong> {data.chronic_conditions}</p>
          <p><strong>Blood Group:</strong> {data.blood_group}</p>
          <p><strong>Allergies:</strong> {data.allergies}</p>
        </div>
      </div>
    </>
  );
}

export default EmergencyProfile;
